The `debounce` function is a utility function that prevents a given function from being called too many times in a short period of time, instead delaying its execution until a specified time has passed since the last call.

```javascript
function debounce(func, wait) {
  let timeout;
  return function(...args) {
    clearTimeout(timeout);
    timeout = setTimeout(() => func(...args), wait);
  };
}

// Example usage:
const debouncedLog = debounce(console.log, 500);
debouncedLog('Hello'); // This will be logged after 500ms
debouncedLog('World'); // This will cancel the previous log and log 'World' after 500ms
```
